import{c as e,S as d,j as a,m as o}from"./chunks/framework.DvQr6YbT.js";const p=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"zh/getting-started/index.md","filePath":"zh/getting-started/index.md","lastUpdated":1783065655000}'),r={name:"zh/getting-started/index.md"};function l(i,t,s,n,c,u){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to “快速开始”">​</a></h1><p>本页介绍如何安装 Knowlery、初始化 vault，以及初始化后会发生什么。</p><h2 id="使用要求" tabindex="-1">使用要求 <a class="header-anchor" href="#使用要求" aria-label="Permalink to “使用要求”">​</a></h2><p>Knowlery 面向 Obsidian desktop，并需要启用 community plugins。</p><p>如果你想让 agent 真正基于 vault 工作，还需要 Claude Code 或 OpenCode。可选工具准备和外部 skill browser 需要 Node.js 与 npm。</p><div class="tip custom-block"><p class="custom-block-title">桌面行为</p><p>Knowlery 会使用本地命令行工具和 Electron desktop API 来支持 agent 相关功能。当前插件 manifest 标记为 desktop-only。</p></div><h2 id="从-community-plugins-安装" tabindex="-1">从 Community plugins 安装 <a class="header-anchor" href="#从-community-plugins-安装" aria-label="Permalink to “从 Community plugins 安装”">​</a></h2><p>日常使用时，请直接从 Obsidian 的 community plugin directory 安装 Knowlery。</p><ol><li>在 Obsidian 中打开 <strong>Settings -&gt; Community plugins</strong>。</li><li>点击 <strong>Browse</strong>。</li><li>搜索 <strong>Knowlery</strong>。</li><li>安装并启用插件。</li></ol><h2 id="使用-brat-安装-beta-版本" tabindex="-1">使用 BRAT 安装 beta 版本 <a class="header-anchor" href="#使用-brat-安装-beta-版本" aria-label="Permalink to “使用 BRAT 安装 beta 版本”">​</a></h2><p>BRAT 是 Obsidian 的 Beta Reviewers Auto-update Tool。只有在你想测试尚未发布到 community plugin directory 的 preview builds 时，才需要使用 BRAT。</p><ol><li>在 Obsidian 中安装 BRAT。</li><li>打开 BRAT 设置。</li><li>添加这个 beta plugin repository：<code>https://github.com/JayJiangCT/knowlery</code>。</li><li>在 <strong>Settings -&gt; Community plugins</strong> 中启用 Knowlery。</li></ol><h2 id="手动安装" tabindex="-1">手动安装 <a class="header-anchor" href="#手动安装" aria-label="Permalink to “手动安装”">​</a></h2><ol><li>从最新 GitHub release 下载 <code>main.js</code>、<code>manifest.json</code> 和 <code>styles.css</code>。</li><li>在你的 vault 中创建 <code>.obsidian/plugins/knowlery/</code>。</li><li>将这三个文件放入该目录。</li><li>重新加载 Obsidian。</li><li>在 <strong>Settings -&gt; Community plugins</strong> 中启用 Knowlery。</li></ol><h2 id="第一次运行" tabindex="-1">第一次运行 <a class="header-anchor" href="#第一次运行" aria-label="Permalink to “第一次运行”">​</a></h2><p>启用插件后，可以从 ribbon 图标或 command palette 打开 Knowlery。</p><p>如果 vault 尚未初始化，Knowlery 会在 dashboard 和 settings tab 中显示 setup 入口。</p><p>Setup wizard 会要求你选择一个平台：</p><table tabindex="0"><thead><tr><th>平台</th><th>生成的配置</th></tr></thead><tbody><tr><td>Claude Code</td><td><code>.claude/CLAUDE.md</code> 和 <code>.claude/rules/</code></td></tr><tr><td>OpenCode</td><td><code>opencode.json</code> 和 <code>.agents/rules/</code></td></tr></tbody></table><p>如果你是从旧版本升级，v0.5.0 新增了 knowledge bundle 的分享与安装：dashboard 的 Bundles 区块、<strong>Share knowledge bundle</strong> 和 <strong>Install knowledge bundle</strong> 命令、存放已安装 bundle 的 <code>Library/</code> 文件夹，以及能感知 bundle 的 <code>/ask</code> skill。v0.4.0 把 dashboard 收敛成一个行动优先的首页，并把 diagnostics、rules、schema shortcuts 和 Skills library 移到 Knowlery settings tab。Bundled skills 仍会在版本变化时自动同步，<code>SCHEMA.md</code> 缺少 anchor sections 时也会就地迁移。custom 和 forked skills 不会被覆盖。</p><p>如果 Knowlery 检测到旧的 BYOAO vault，setup wizard 会切换到 migration mode，并保留原有 BYOAO/OpenCode 文件，同时改为 Knowlery 的 Claude Code 配置。</p><h2 id="setup-会创建什么" tabindex="-1">Setup 会创建什么 <a class="header-anchor" href="#setup-会创建什么" aria-label="Permalink to “Setup 会创建什么”">​</a></h2><p>Knowlery 会在 vault 中创建知识工作区和 agent 配置：</p><table tabindex="0"><thead><tr><th>路径</th><th>用途</th></tr></thead><tbody><tr><td><code>KNOWLEDGE.md</code></td><td>给人和 agent 看的 vault 操作指南</td></tr><tr><td><code>SCHEMA.md</code></td><td>知识分类与页面约定</td></tr><tr><td><code>INDEX.base</code></td><td>编译知识页面的 Obsidian Bases 索引</td></tr><tr><td><code>entities/</code></td><td>人、工具、组织、项目等命名对象</td></tr><tr><td><code>concepts/</code></td><td>想法、框架、理论、心智模型</td></tr><tr><td><code>comparisons/</code></td><td>并排比较分析</td></tr><tr><td><code>queries/</code></td><td>保存的问题和研究线索</td></tr><tr><td><code>.knowlery/manifest.json</code></td><td>Knowlery setup 元数据</td></tr><tr><td><code>.agents/skills/</code></td><td>skills 的 canonical 存放位置</td></tr><tr><td><code>.agents/rules/</code></td><td>OpenCode rules 和共享 agent rules</td></tr><tr><td><code>.claude/skills/</code></td><td>为 Claude Code 镜像的内置 skills</td></tr><tr><td><code>.claude/CLAUDE.md</code></td><td>Claude Code vault instructions</td></tr><tr><td><code>.claude/rules/</code></td><td>Claude Code rules</td></tr><tr><td><code>opencode.json</code></td><td>OpenCode 配置</td></tr><tr><td><code>skills-lock.json</code></td><td>skill 来源、版本、禁用状态</td></tr></tbody></table><p>正常使用过程中，Knowlery 还可能在 <code>.knowlery/</code> 下创建私有 activity receipts、weekly summary reports、daily review request/result 文件，以及 Freshness Review 的 request/result/sidecar 文件。</p><h2 id="可选工具准备" tabindex="-1">可选工具准备 <a class="header-anchor" href="#可选工具准备" aria-label="Permalink to “可选工具准备”">​</a></h2><p>Setup wizard 可以检测 Claude Code、OpenCode、Node.js、Claudian 和 skills tooling。</p><p>缺失的可选工具会显示为可选择的安装或准备步骤。已安装工具会显示为只读状态行。这些动作都是 opt-in，并且会以你的本机用户权限运行。</p><h2 id="打开-dashboard" tabindex="-1">打开 Dashboard <a class="header-anchor" href="#打开-dashboard" aria-label="Permalink to “打开 Dashboard”">​</a></h2><p>Setup 完成后，打开 Knowlery dashboard。它是一个单页滚动的 review surface：</p><table tabindex="0"><thead><tr><th>区块</th><th>用途</th></tr></thead><tbody><tr><td>Today&#39;s move</td><td>从当前活动上下文开始，选择一个小的下一步</td></tr><tr><td>Suggested moves</td><td>使用 Process new material 或 Challenge an idea 等可复用 review prompts</td></tr><tr><td>Knowledge health</td><td>有 Freshness Review suggestions 时进行 review</td></tr><tr><td>This note</td><td>review 当前 Markdown 笔记并准备专注的 prompt</td></tr><tr><td>Recent activity</td><td>查看私有 activity receipts，并打开完整 activity 列表</td></tr><tr><td>This week</td><td>生成 weekly summary、打开上次报告，或发送给 agent review</td></tr><tr><td>Bundles</td><td>分享 review 过的 knowledge bundle，或安装别人分享给你的 bundle</td></tr></tbody></table><p>打开 <strong>Settings -&gt; Knowlery</strong> 可以进行 diagnostics、rules/schema shortcuts、Skills library、平台切换、activity logging 和 maintenance actions。</p><h2 id="推荐的第一次使用方式" tabindex="-1">推荐的第一次使用方式 <a class="header-anchor" href="#推荐的第一次使用方式" aria-label="Permalink to “推荐的第一次使用方式”">​</a></h2><ol><li>先在一个干净 test vault 中初始化。</li><li>阅读生成的 <code>KNOWLEDGE.md</code> 和 <code>SCHEMA.md</code>。</li><li>打开 dashboard，查看 Today&#39;s move、Suggested moves 和 This note。</li><li>往 vault 中加入一两篇真实笔记。</li><li>生成一次 weekly summary，然后打开 <strong>Settings -&gt; Knowlery</strong> 运行诊断。</li></ol>',34)])])}const b=e(r,[["render",l]]);export{p as __pageData,b as default};
